import{_ as a,o as t,c as s,ae as d}from"./chunks/framework.CylwKCfq.js";const u=JSON.parse('{"title":"Claude Code Skill: /trace-graph","description":"","frontmatter":{},"headers":[],"relativePath":"guide/claude-code-skill.md","filePath":"guide/claude-code-skill.md"}'),o={name:"guide/claude-code-skill.md"};function n(r,e,l,i,c,p){return t(),s("div",null,[...e[0]||(e[0]=[d(`<h1 id="claude-code-skill-trace-graph" tabindex="-1">Claude Code Skill: <code>/trace-graph</code> <a class="header-anchor" href="#claude-code-skill-trace-graph" aria-label="Permalink to &quot;Claude Code Skill: \`/trace-graph\`&quot;">​</a></h1><p>TxGraph ships with a built-in <a href="https://claude.com/claude-code" target="_blank" rel="noreferrer">Claude Code</a> skill that lets you trace blockchain addresses directly from your terminal through a conversational workflow.</p><h2 id="what-it-does" tabindex="-1">What It Does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What It Does&quot;">​</a></h2><p>The <code>/trace-graph</code> skill guides you through specifying parameters, starts the local demo, and opens the resulting transaction graph in your browser — all without leaving the CLI.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><a href="https://claude.com/claude-code" target="_blank" rel="noreferrer">Claude Code</a> installed</li><li>Node.js &gt;= 18, pnpm &gt;= 8</li><li>A TrustIn API key (contact <a href="mailto:info@trustin.info" target="_blank" rel="noreferrer">info@trustin.info</a>)</li></ul><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>In the txgraph project directory, run Claude Code and type:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/trace-graph</span></span></code></pre></div><p>Claude will walk you through the following steps:</p><h3 id="_1-specify-parameters" tabindex="-1">1. Specify Parameters <a class="header-anchor" href="#_1-specify-parameters" aria-label="Permalink to &quot;1. Specify Parameters&quot;">​</a></h3><p>You&#39;ll be prompted for:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Required</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>address</code></td><td>Yes</td><td>Blockchain address to trace</td><td>—</td></tr><tr><td><code>chain</code></td><td>Auto</td><td>Ethereum or Tron (auto-detected from address format)</td><td>—</td></tr><tr><td><code>direction</code></td><td>No</td><td><code>out</code>, <code>in</code>, or <code>all</code></td><td><code>out</code></td></tr><tr><td><code>from_date</code></td><td>No</td><td>Start date filter (<code>YYYY-MM-DD</code>)</td><td>—</td></tr><tr><td><code>to_date</code></td><td>No</td><td>End date filter (<code>YYYY-MM-DD</code>)</td><td>—</td></tr></tbody></table><p><strong>Chain auto-detection:</strong></p><ul><li><code>0x</code> + 40 hex chars → Ethereum</li><li><code>T</code> + 33 base58 chars → Tron</li></ul><h3 id="_2-environment-setup" tabindex="-1">2. Environment Setup <a class="header-anchor" href="#_2-environment-setup" aria-label="Permalink to &quot;2. Environment Setup&quot;">​</a></h3><p>Claude checks that everything is ready:</p><ul><li>Creates <code>examples/local-demo/.env</code> with your API key if missing</li><li>Installs dependencies if needed</li><li>Builds the core <code>@trustin/txgraph</code> package</li></ul><h3 id="_3-launch-open" tabindex="-1">3. Launch &amp; Open <a class="header-anchor" href="#_3-launch-open" aria-label="Permalink to &quot;3. Launch &amp; Open&quot;">​</a></h3><p>Claude starts the Vite dev server and opens a deep-link URL in your browser:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:5173/?address=TN3W4H6rK2ce4vX9YnFQHwKENnHjoxb3m9&amp;chain=Tron&amp;direction=out</span></span></code></pre></div><p>The demo app auto-explores on load — the graph appears immediately.</p><h2 id="example-session" tabindex="-1">Example Session <a class="header-anchor" href="#example-session" aria-label="Permalink to &quot;Example Session&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You: /trace-graph</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: What address would you like to trace?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You: TN3W4H6rK2ce4vX9YnFQHwKENnHjoxb3m9</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Detected chain: Tron. Direction?  [Outflow / Inflow / All]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You: Outflow</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Starting dev server...</span></span>
<span class="line"><span>        Graph opened in browser:</span></span>
<span class="line"><span>          Address:   TN3W4H6rK2ce4vX9YnFQHwKENnHjoxb3m9</span></span>
<span class="line"><span>          Chain:     Tron</span></span>
<span class="line"><span>          Direction: out</span></span>
<span class="line"><span>          URL:       http://localhost:5173/?address=TN3W4...&amp;chain=Tron&amp;direction=out</span></span></code></pre></div><h2 id="url-deep-link-parameters" tabindex="-1">URL Deep-Link Parameters <a class="header-anchor" href="#url-deep-link-parameters" aria-label="Permalink to &quot;URL Deep-Link Parameters&quot;">​</a></h2><p>You can also open the demo directly with query parameters (no skill needed):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:5173/?address=0xd8dA6BF26964aF9D7eEd9e03E53415D37aA96045&amp;chain=Ethereum&amp;direction=out&amp;from=2024-01-01&amp;to=2024-12-31</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Param</th><th>Description</th></tr></thead><tbody><tr><td><code>address</code></td><td>Blockchain address (triggers auto-explore)</td></tr><tr><td><code>chain</code></td><td><code>Ethereum</code> or <code>Tron</code></td></tr><tr><td><code>direction</code></td><td><code>in</code>, <code>out</code>, or <code>all</code></td></tr><tr><td><code>from</code></td><td>Start date (<code>YYYY-MM-DD</code>)</td></tr><tr><td><code>to</code></td><td>End date (<code>YYYY-MM-DD</code>)</td></tr></tbody></table><h2 id="skill-file-location" tabindex="-1">Skill File Location <a class="header-anchor" href="#skill-file-location" aria-label="Permalink to &quot;Skill File Location&quot;">​</a></h2><p>The skill is defined at <code>.claude/skills/trace-graph.md</code> in the project root. You can customize the workflow by editing this file.</p>`,30)])])}const m=a(o,[["render",n]]);export{u as __pageData,m as default};
